test('run detail page tabbed UI: 5 tabs, URL-driven tab state, navigation', async ({ page }) => {
	await page.route('/graphql', async (route) => {
		const body = route.request().postDataJSON() as {
			query: string;
			variables?: Record<string, unknown>;
		};

		if (body.query.includes('NodeInfo')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({ data: { nodeInfo: NODE_INFO } })
			});
			return;
		}
		if (body.query.includes('ProjectsForLayout') || body.query.includes('Projects')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({ data: { projects: { edges: PROJECTS.map((node) => ({ node })) } } })
			});
			return;
		}
		if (body.query.includes('RunHeader') || body.query.includes('RunDetailExpand')) {
			const id = body.variables?.['id'] as string;
			const r = ALL_RUNS.find((n) => n.id === id) ?? null;
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({ data: { run: r } })
			});
			return;
		}
		if (body.query.includes('ParentRunParent')) {
			const id = body.variables?.['id'] as string;
			const r = ALL_RUNS.find((n) => n.id === id);
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({ data: { run: r ? { parentRunId: r.parentRunId } : null } })
			});
			return;
		}
		if (body.query.includes('RunExecutionExpand')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({
					data: {

					projectID: data.projectId,
					first: PAGE_SIZE,
					after: pageInfo.endCursor,
					mediaType: data.mediaType ?? undefined,
					search: q ? q : undefined,
					sort: data.sort,
					staleness: data.staleness ?? undefined,
					phase: data.phase ?? undefined,
					prefix: data.prefix && data.prefix.length > 0 ? data.prefix : undefined
				})
			);
			if (outcome.stale) return;
			allEdges = [...allEdges, ...outcome.value.artifacts.edges];
			pageInfo = outcome.value.artifacts.pageInfo;
		} finally {
			loading = false;
		}
	}

	// Render a server-supplied snippet to HTML. The resolver wraps the matched
	// substring in markdown emphasis ("**…**"); we escape the rest and convert
	// the marker pairs to <mark> for visual highlighting. Only the first
	// matching pair is highlighted (resolver emits a single match per snippet).
	function escapeHtml(s: string): string {
		return s
			.replace(/&/g, '&amp;')
			.replace(/</g, '&lt;')
			.replace(/>/g, '&gt;')
			.replace(/"/g, '&quot;')
			.replace(/'/g, '&#39;');
	}
	function renderSnippet(snippet: string): string {
		const escaped = escapeHtml(snippet);
		return escaped.replace(
			/\*\*([\s\S]+?)\*\*/,
			'<mark class="rounded bg-yellow-200 px-0.5 text-fg-ink dark:bg-yellow-500/40 dark:text-dark-fg-ink">$1</mark>'
		);
	}

	function stalenessBadge(staleness: string): { label: string; cls: string } {
		switch (staleness) {
			case 'fresh':
				return {
					label: 'fresh',
					cls: 'bg-green-100 text-green-800 dark:bg-green-900/30 dark:text-green-400'
				};
			case 'stale':
				return {
					label: 'stale',
					cls: 'bg-amber-100 text-amber-800 dark:bg-amber-900/30 dark:text-amber-400'
				};
			case 'missing':
				return {
					label: 'missing',
					cls: 'bg-red-100 text-red-800 dark:bg-red-900/30 dark:text-red-400'
				};
			default:
				return {
					label: staleness,
					cls: 'bg-bg-surface text-fg-muted dark:bg-dark-bg-surface dark:text-dark-fg-muted'
				};
		}
	}
</script>

