import type { PageLoad } from './$types'
import { createClient } from '$lib/gql/client'
import { gql } from 'graphql-request'

export const RUNS_QUERY = gql`
	query NodeRuns($first: Int, $after: String, $layer: RunLayer, $status: String) {
		runs(first: $first, after: $after, layer: $layer, status: $status) {
			edges {
				node {
					id
					layer
					status
					projectID
					beadId
					startedAt
					durationMs
				}
				cursor
			}
			pageInfo {
				hasNextPage
				endCursor
			}
			totalCount
		}
		projects {
			edges {
				node {
					id
					name
				}
			}
		}
	}
`

const FEDERATED_RUNS_QUERY = gql`
	query FederatedRuns($layer: RunLayer, $projectID: String) {
		federatedRuns(layer: $layer, projectID: $projectID) {
			nodeId
			projectId
			projectUrl
			writeCapability
			status
			run {
				id
				layer
				status
				projectID
				beadId
				startedAt
				durationMs
			}
		}
		projects {
			edges {
				node {
					id
					name
				}
			}
		}
	}
`

export interface RunNode {
	id: string
	layer: string
	status: string
	projectID: string | null
	beadId: string | null
	startedAt: string | null
	durationMs: number | null
}

export interface RunEdge {
	node: RunNode
	cursor: string
}

export interface PageInfo {
	hasNextPage: boolean
	endCursor: string | null
}

export interface RunConnection {
	edges: RunEdge[]
	pageInfo: PageInfo
	totalCount: number
}

interface ProjectNode {
	id: string
	name: string
}

interface QueryResult {
	runs: RunConnection
	projects: {
		edges: Array<{ node: ProjectNode }>
	}
}

export interface FederatedRunRow {
	nodeId: string
	projectId: string | null
	projectUrl: string
	writeCapability: boolean
	status: string
	run: RunNode
}

interface FederatedQueryResult {
	federatedRuns: FederatedRunRow[]
	projects: { edges: Array<{ node: ProjectNode }> }
}

export const PAGE_SIZE = 50

export const load: PageLoad = async ({ params, url, fetch }) => {
	const layer = url.searchParams.get('layer') ?? null
	const status = url.searchParams.get('status') ?? null
	const scope = url.searchParams.get('scope') === 'federation' ? 'federation' : 'local'

	const client = createClient(fetch as unknown as typeof globalThis.fetch)

	if (scope === 'federation') {
		try {
			const data = await client.request<FederatedQueryResult>(FEDERATED_RUNS_QUERY, {
				layer: layer ?? undefined
			})
			const projectNames: Record<string, string> = {}
			for (const { node } of data.projects.edges) projectNames[node.id] = node.name

			const filtered = status
				? data.federatedRuns.filter((row) => row.run.status === status)
				: data.federatedRuns

			const edges: RunEdge[] = filtered.map((row, i) => ({
				node: row.run,
				cursor: `fed:${i}`
			}))
			const federationByRunId: Record<string, FederatedRunRow> = {}
			for (const row of filtered) federationByRunId[row.run.id] = row

			return {
				nodeId: params.nodeId,
				runs: {
					edges,
					pageInfo: { hasNextPage: false, endCursor: null },
					totalCount: edges.length
				} as RunConnection,
				projects: data.projects.edges.map((e) => e.node),
				projectNames,
				activeLayer: layer,
				activeStatus: status,
				scope: 'federation' as const,
				federationByRunId,
				federationError: null as string | null
			}
		} catch (e) {
			return {
				nodeId: params.nodeId,
				runs: {
					edges: [] as RunEdge[],
					pageInfo: { hasNextPage: false, endCursor: null },
					totalCount: 0
				} as RunConnection,
				projects: [] as ProjectNode[],
				projectNames: {} as Record<string, string>,
				activeLayer: layer,
				activeStatus: status,
				scope: 'federation' as const,
				federationByRunId: {} as Record<string, FederatedRunRow>,
				federationError: (e as Error).message
			}
		}
	}

	const data = await client.request<QueryResult>(RUNS_QUERY, {
		first: PAGE_SIZE,
		layer: layer ?? undefined,
		status: status ?? undefined
	})

	const projectNames: Record<string, string> = {}
	for (const { node } of data.projects.edges) {
		projectNames[node.id] = node.name
	}

	return {
		nodeId: params.nodeId,
		runs: data.runs,
		projects: data.projects.edges.map((e) => e.node),
		projectNames,
		activeLayer: layer,
		activeStatus: status,
		scope: 'local' as const,
		federationByRunId: {} as Record<string, FederatedRunRow>,
		federationError: null as string | null
	}
}

import { defineConfig } from '@playwright/test';
import path from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));

// The default Playwright harness boots the Go DDx server against a temp copy
// of e2e/fixtures/ so the API endpoints exercised by TC-008 (and other
// backend-dependent specs) return real data without reading the developer's
// $HOME or the repository's live .ddx/ state.

const CLI_PKG_DIR = path.resolve(__dirname, '../../..');
const FRONTEND_DIR = __dirname;
const FIXTURE_DIR = path.resolve(__dirname, 'e2e/fixtures');
const PORT = Number(process.env.DDX_E2E_PORT ?? 4174);
const BASE_URL = `https://127.0.0.1:${PORT}`;

// Build the SvelteKit frontend (so cli/internal/server/embed.go has assets to
// embed), copy the fixture workspace into a fresh temp dir, build the ddx
// binary from the cli module, and exec it from the temp dir. The temp dir has
// no .git so FindProjectRoot falls back to it, and tsnet is disabled so the
// harness has no Tailscale dependency.
const bootCommand = [
	`set -e`,
	`(cd "${FRONTEND_DIR}" && bun run build >&2)`,
	`TMP=$(mktemp -d -t ddx-e2e-XXXXXX)`,
	`cp -R "${FIXTURE_DIR}/." "$TMP/"`,
	`(cd "${CLI_PKG_DIR}" && go build -o "$TMP/ddx" .)`,
	`cd "$TMP"`,
	`DDX_OPERATOR_PROMPT_ALLOWLIST=localhost exec ./ddx server --tsnet=false --addr=127.0.0.1 --port=${PORT}`
].join(' && ');

export default defineConfig({
	webServer: {
		command: `bash -c '${bootCommand}'`,
		url: `${BASE_URL}/api/health`,
		ignoreHTTPSErrors: true,
		reuseExistingServer: !process.env.CI,
		timeout: 180_000,
		stdout: 'pipe',
		stderr: 'pipe'
	},
	use: {
		baseURL: BASE_URL,
		ignoreHTTPSErrors: true
	},
	testMatch: ['**/*.e2e.{ts,js}', 'e2e/**/*.spec.ts']
});

